module asyn_fifo (
    input wclk, 
    input rclk, 
    input wrstn, 
    input rrstn, 
    input winc, 
    input rinc, 
    input [7:0] wdata, 
    output wfull, 
    output rempty, 
    output [7:0] rdata
);

wire [7:0] ram_data;
wire [7:0] ram_addr;
wire ram_wen;
wire ram_ren;
wire [7:0] ram_din;
wire [7:0] ram_dout;
wire [7:0] ram_mem [0:15];

reg [3:0] waddr_bin;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr_bin <= 4'b0000;
    end else if (winc) begin
        waddr_bin <= waddr_bin + 1;
    end
end
wire [3:0] wptr;
assign wptr[0] = waddr_bin[0];
assign wptr[1] = waddr_bin[1] ^ waddr_bin[0];
assign wptr[2] = waddr_bin[2] ^ waddr_bin[1];
assign wptr[3] = waddr_bin[3] ^ waddr_bin[2];
reg [3:0] wptr_buff;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr_buff <= 4'b0000;
    end else begin
        wptr_buff <= wptr;
    end
end

reg [3:0] raddr_bin;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr_bin <= 4'b0000;
    end else if (rinc) begin
        raddr_bin <= raddr_bin + 1;
    end
end
wire [3:0] rptr;
assign rptr[0] = raddr_bin[0];
assign rptr[1] = raddr_bin[1] ^ raddr_bin[0];
assign rptr[2] = raddr_bin[2] ^ raddr_bin[1];
assign rptr[3] = raddr_bin[3] ^ raddr_bin[2];
reg [3:0] rptr_buff;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr_buff <= 4'b0000;
    end else begin
        rptr_buff <= rptr;
    end
end

wire [3:0] wptr_syn;
assign wptr_syn = wptr_buff;
wire [3:0] rptr_syn;
assign rptr_syn = rptr_buff;
assign wfull = (wptr_syn == {~rptr_syn[3], rptr_syn[2:0]});
assign rempty = (rptr_syn == wptr_syn);

assign ram_wen = winc;
assign ram_ren = rinc;
assign ram_addr = waddr_bin;
assign ram_din = wdata;
assign ram_dout = ram_data;

genvar i;
for(i = 0; i < 16; i=i+1) begin: mem_gen
    end // Auto-repaired
    always @(posedge wclk) begin
        if(ram_wen) begin
            ram_mem[i] <= ram_din;
        end
    end
end

assign rdata = ram_dout;
endmodule
